commands.cmd:
meminfo=$(cat /proc/meminfo) || { echo "meminfo unreadable" >&2; exit 1; }
printf '%s\n' "$meminfo" | awk '
  /^HugePages_Total:/{t=$2}
  /^HugePages_Free:/{f=$2}
  /^Hugepagesize:/{sz=$2}
  END{
    printf "{\"hugepages_total\":%d,\"hugepages_free\":%d,\"hugepagesize_kb\":%d,\"hugepages_free_pct\":\"%.1f\"}",
      t, f, sz, (t>0 ? f/t*100 : 0)
  }' || exit 1
